UPDATE inspection_record
production_line_id = #{record.productionLineId}, route_id = #{record.routeId}, route_code = #{record.routeCode}, route_name = #{record.routeName}, plan_date = #{record.planDate}, current_result = #{record.currentResult}, abnormal_type = #{record.abnormalType}, abnormal_phenomenon = #{record.abnormalPhenomenon}, plan_source = #{record.planSource}, standard_code = #{record.standardCode}, part_code = #{record.partCode}, part_name = #{record.partName}, inspection_part = #{record.inspectionPart}, inspection_content = #{record.inspectionContent}, completed_at = #{record.completedAt}, implementation_cycle = #{record.implementationCycle}, cycle_unit = #{record.cycleUnit}, completion_flag = #{record.completionFlag}, qualitative_standard = #{record.qualitativeStandard}, standard_category = #{record.standardCategory}, quantitative_standard = #{record.quantitativeStandard}, unit_of_measurement = #{record.unitOfMeasurement}, upper_limit = #{record.upperLimit}, lower_limit = #{record.lowerLimit}, id_location_code = #{record.idLocationCode}, id_location_name = #{record.idLocationName}, abnormal_contact_sheet = #{record.abnormalContactSheet}, updated_at = #{record.updatedAt},
WHERE id = #{record.id} AND creator_id = #{creatorId}

