    AND ir.creator_id = #{creatorId}
    AND ir.production_line_id = #{productionLineId}
    AND ir.route_id = #{routeId}
    AND ir.plan_date >= #{planDateStart}
    AND ir.plan_date <= #{planDateEnd}
    AND ir.completion_flag = #{completionFlag}
    AND ir.part_code LIKE CONCAT('%', #{partCode}, '%')
    AND ir.part_name LIKE CONCAT('%', #{partName}, '%')

ORDER BY ir.id DESC

SELECT MIN(ir.id) AS id, ir.production_line_id AS productionLineId, pl.line_name AS productionLineName, ir.route_code AS routeCode, ir.route_name AS routeName, ir.plan_source AS planSource, COUNT(1) AS totalCount, SUM(CASE WHEN ir.completion_flag = 'Y' THEN 1 ELSE 0 END) AS inspectedCount, SUM(CASE WHEN ir.completion_flag = 'Y' THEN 0 ELSE 1 END) AS remainingCount FROM inspection_record ir LEFT JOIN production_line pl ON ir.production_line_id = pl.id
AND ir.creator_id = #{creatorId} AND ir.production_line_id = #{productionLineId} AND ir.route_name LIKE CONCAT('%', #{routeName}, '%') AND ir.plan_source = #{planSource}
GROUP BY ir.production_line_id, pl.line_name, ir.route_code, ir.route_name, ir.plan_source ORDER BY MIN(ir.id) DESC


WHERE ir.inspection_standard_id = #{inspectionStandardId}
AND ir.creator_id = #{creatorId}
ORDER BY ir.id DESC
